/// <summary>
/// The class <c>ETG_InventBatchTableEventHandler</c> is used to handle the Event Handlers related to <c>InventBatch</c> Table.
/// </summary>
class ETG_InventBatchTableEventHandler
{
}

Method.Source:
/// <summary>
/// If user enters the Vendor Batch date,then check box "Use as manufacturing date" which is next to the Vendor Batch Date field should be automtically updated.
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[DataEventHandler(tableStr(InventBatch), DataEventType::ModifiedField)]
public static void InventBatch_onModifiedField(Common sender, DataEventArgs e)
{
    ModifyFieldEventArgs    event       = e as DataEventArgs;
    InventBatch             inventBatch = sender as InventBatch;
    FieldId                 fieldId     = event.parmFieldId();

    switch(fieldId)
    {
        case fieldNum(InventBatch, PdsVendBatchDate):
            inventBatch.PdsUseVendBatchDate = inventBatch.PdsVendBatchDate ? NoYes::Yes : NoYes::No;
            break;
    }
}
